INSERT INTO \`temple_sevas\` (\`id\`, \`name_gu\`, \`name_hi\`, \`name_en\`, \`description_gu\`, \`description_hi\`, \`description_en\`, \`category\`, \`price\`, \`min_price\`, \`is_variable_price\`, \`image_path\`, \`slot_config\`, \`notification_config\`, \`linked_products\`, \`requires_booking\`, \`is_active\`, \`sort_order\`, \`assignee_id\`, \`created_at\`, \`updated_at\`, \`deleted_at\`) VALUES ('1', 'શ્રૃંગાર સેવા', 'श्रृंगार सेवा', 'Shringar Seva', 'હનુમાનજી મહારાજની શ્રૃંગાર સેવા. ભગવાનને ફૂલ, માળા અને શ્રૃંગાર સામગ્રીથી સજાવવામાં આવે છે.', 'हनुमानजी महाराज की श्रृंगार सेवा. भगवान को फूल, माला और श्रृंगार सामग्री से सजाया जाता है.', 'Shringar Seva of Hanumanji Maharaj. The deity is adorned with flowers, garlands and decorative items.', 'shringar', '1100.00', NULL, '0', NULL, '{\"slot_duration_minutes\":\"30\",\"max_bookings_per_slot\":1,\"acceptance_period\":{\"type\":\"perpetual\"},\"weekly_schedule\":{\"default\":[\"06:00\",\"09:00\",\"12:00\",\"16:46\",\"17:00\"],\"monday\":null,\"tuesday\":null,\"wednesday\":null,\"thursday\":null,\"friday\":null,\"saturday\":null,\"sunday\":null},\"blackout_dates\":[{\"date\":\"2026-12-11\",\"reason\":\"Temple closed\"}],\"version\":2}', '{\"notify_on_booking\":false,\"booking_channels\":[],\"reminders\":[]}', '{\"type\":\"category\",\"category_id\":\"1\",\"label_gu\":\"Vastra Pasand Karo\",\"label_en\":\"Choose Offering\"}', '1', '1', '1', '1', '2026-03-31 14:31:36', '2026-04-09 10:49:45', NULL);
INSERT INTO \`temple_sevas\` (\`id\`, \`name_gu\`, \`name_hi\`, \`name_en\`, \`description_gu\`, \`description_hi\`, \`description_en\`, \`category\`, \`price\`, \`min_price\`, \`is_variable_price\`, \`image_path\`, \`slot_config\`, \`notification_config\`, \`linked_products\`, \`requires_booking\`, \`is_active\`, \`sort_order\`, \`assignee_id\`, \`created_at\`, \`updated_at\`, \`deleted_at\`) VALUES ('2', 'વસ્ત્ર સેવા', 'वस्त्र सेवा', 'Vastra Seva', 'હનુમાનજી મહારાજને નવા વસ્ત્રો અર્પણ કરવાની સેવા.', 'हनुमानजी महाराज को नए वस्त्र अर्पण करने की सेवा.', 'Offering new garments to Hanumanji Maharaj.', 'vastra', '501.00', NULL, '0', NULL, '{\"version\":2,\"slot_duration_minutes\":60,\"max_bookings_per_slot\":1,\"acceptance_period\":{\"type\":\"perpetual\",\"start_date\":null,\"end_date\":null},\"weekly_schedule\":{\"default\":[\"07:00\",\"11:00\",\"16:00\"],\"monday\":null,\"tuesday\":null,\"wednesday\":null,\"thursday\":null,\"friday\":null,\"saturday\":null,\"sunday\":null},\"blackout_dates\":[]}', NULL, NULL, '1', '1', '2', '1', '2026-03-31 14:31:36', '2026-04-09 07:01:23', NULL);
INSERT INTO \`temple_sevas\` (\`id\`, \`name_gu\`, \`name_hi\`, \`name_en\`, \`description_gu\`, \`description_hi\`, \`description_en\`, \`category\`, \`price\`, \`min_price\`, \`is_variable_price\`, \`image_path\`, \`slot_config\`, \`notification_config\`, \`linked_products\`, \`requires_booking\`, \`is_active\`, \`sort_order\`, \`assignee_id\`, \`created_at\`, \`updated_at\`, \`deleted_at\`) VALUES ('3', 'અન્નદાન સેવા', 'अन्नदान सेवा', 'Annadan Seva', 'ભોજનાલયમાં અન્નદાન સેવા. ભક્તોને પ્રસાદ ભોજન પીરસવામાં આવે છે.', 'भोजनालय में अन्नदान सेवा. भक्तों को प्रसाद भोजन परोसा जाता है.', 'Annadan Seva at the temple kitchen. Prasad meals are served to devotees.', 'annadan', '2100.00', NULL, '0', NULL, '{\"version\":2,\"slot_duration_minutes\":60,\"max_bookings_per_slot\":1,\"acceptance_period\":{\"type\":\"perpetual\",\"start_date\":null,\"end_date\":null},\"weekly_schedule\":{\"default\":[\"11:00\",\"18:00\"],\"monday\":null,\"tuesday\":null,\"wednesday\":null,\"thursday\":null,\"friday\":null,\"saturday\":null,\"sunday\":null},\"blackout_dates\":[]}', NULL, NULL, '1', '1', '3', '1', '2026-03-31 14:31:36', '2026-04-09 07:01:23', NULL);
INSERT INTO \`temple_sevas\` (\`id\`, \`name_gu\`, \`name_hi\`, \`name_en\`, \`description_gu\`, \`description_hi\`, \`description_en\`, \`category\`, \`price\`, \`min_price\`, \`is_variable_price\`, \`image_path\`, \`slot_config\`, \`notification_config\`, \`linked_products\`, \`requires_booking\`, \`is_active\`, \`sort_order\`, \`assignee_id\`, \`created_at\`, \`updated_at\`, \`deleted_at\`) VALUES ('4', 'મહાભિષેક પૂજા', 'महाभिषेक पूजा', 'Mahabhishek Puja', 'હનુમાનજી મહારાજનો મહાભિષેક. દૂધ, દહીં, ઘી, મધ અને ગંગાજળથી અભિષેક કરવામાં આવે છે.', 'हनुमानजी महाराज का महाभिषेक. दूध, दही, घी, शहद और गंगाजल से अभिषेक किया जाता है.', 'Mahabhishek of Hanumanji Maharaj. Abhishek performed with milk, curd, ghee, honey and Gangajal.', 'puja', '5100.00', NULL, '0', NULL, '{\"version\":2,\"slot_duration_minutes\":60,\"max_bookings_per_slot\":1,\"acceptance_period\":{\"type\":\"perpetual\",\"start_date\":null,\"end_date\":null},\"weekly_schedule\":{\"default\":[\"05:30\",\"10:00\",\"16:30\"],\"monday\":null,\"tuesday\":null,\"wednesday\":null,\"thursday\":null,\"friday\":null,\"saturday\":null,\"sunday\":null},\"blackout_dates\":[]}', NULL, NULL, '1', '1', '4', '1', '2026-03-31 14:31:36', '2026-04-09 07:01:23', NULL);
INSERT INTO \`temple_sevas\` (\`id\`, \`name_gu\`, \`name_hi\`, \`name_en\`, \`description_gu\`, \`description_hi\`, \`description_en\`, \`category\`, \`price\`, \`min_price\`, \`is_variable_price\`, \`image_path\`, \`slot_config\`, \`notification_config\`, \`linked_products\`, \`requires_booking\`, \`is_active\`, \`sort_order\`, \`assignee_id\`, \`created_at\`, \`updated_at\`, \`deleted_at\`) VALUES ('5', 'સુંદરકાંડ પાઠ', 'सुंदरकांड पाठ', 'Sundarkand Path', 'સુંદરકાંડનો સામૂહિક પાઠ. તુલસીદાસ રચિત રામચરિતમાનસના સુંદરકાંડનો પાઠ.', 'सुंदरकांड का सामूहिक पाठ. तुलसीदास रचित रामचरितमानस के सुंदरकांड का पाठ.', 'Collective recitation of Sundarkand from Tulsidas\' Ramcharitmanas.', 'special', '2501.00', NULL, '0', NULL, '{\"version\":2,\"slot_duration_minutes\":60,\"max_bookings_per_slot\":1,\"acceptance_period\":{\"type\":\"perpetual\",\"start_date\":null,\"end_date\":null},\"weekly_schedule\":{\"default\":[\"17:00\"],\"monday\":null,\"tuesday\":null,\"wednesday\":null,\"thursday\":null,\"friday\":null,\"saturday\":null,\"sunday\":null},\"blackout_dates\":[]}', NULL, NULL, '1', '1', '5', '1', '2026-03-31 14:31:36', '2026-04-09 07:01:23', NULL);
INSERT INTO \`temple_sevas\` (\`id\`, \`name_gu\`, \`name_hi\`, \`name_en\`, \`description_gu\`, \`description_hi\`, \`description_en\`, \`category\`, \`price\`, \`min_price\`, \`is_variable_price\`, \`image_path\`, \`slot_config\`, \`notification_config\`, \`linked_products\`, \`requires_booking\`, \`is_active\`, \`sort_order\`, \`assignee_id\`, \`created_at\`, \`updated_at\`, \`deleted_at\`) VALUES ('6', 'સામાન્ય દાન', 'सामान्य दान', 'General Donation', 'મંદિરના વિકાસ અને સેવા કાર્યો માટે સામાન્ય દાન.', 'मंदिर के विकास और सेवा कार्यों के लिए सामान्य दान.', 'General donation for temple development and service activities.', 'other', '100.00', '100.00', '1', NULL, NULL, NULL, NULL, '0', '1', '6', '1', '2026-03-31 14:31:36', '2026-03-31 14:31:36', NULL);
