INSERT INTO \`temple_events\` (\`id\`, \`title_gu\`, \`title_hi\`, \`title_en\`, \`description_gu\`, \`description_hi\`, \`description_en\`, \`start_date\`, \`end_date\`, \`start_time\`, \`end_time\`, \`location\`, \`image_path\`, \`is_featured\`, \`status\`, \`event_type\`, \`created_by\`, \`created_at\`, \`updated_at\`, \`deleted_at\`) VALUES ('1', 'હનુમાન જયંતિ મહોત્સવ', 'हनुमान जयंती महोत्सव', 'Hanuman Jayanti Celebration', 'શ્રી પાતળિયા હનુમાનજી ધામ ખાતે હનુમાન જયંતિનો ભવ્ય ઉત્સવ. સવારે વિશેષ અભિષેક, મહાપૂજા, સુંદરકાંડ પાઠ, ભંડારા અને સાંજે ભવ્ય આરતી.', 'श्री पातळिया हनुमानजी धाम पर हनुमान जयंती का भव्य उत्सव।', NULL, '2026-04-15', '2026-04-15', '05:00:00', '21:00:00', 'Shree Pataliya Hanumanji Temple, Antarjal', NULL, '1', 'published', 'festival', NULL, '2026-03-31 14:31:36', '2026-03-31 14:31:36', NULL);
INSERT INTO \`temple_events\` (\`id\`, \`title_gu\`, \`title_hi\`, \`title_en\`, \`description_gu\`, \`description_hi\`, \`description_en\`, \`start_date\`, \`end_date\`, \`start_time\`, \`end_time\`, \`location\`, \`image_path\`, \`is_featured\`, \`status\`, \`event_type\`, \`created_by\`, \`created_at\`, \`updated_at\`, \`deleted_at\`) VALUES ('2', 'શ્રી રામ નવમી ઉત્સવ', 'श्री राम नवमी उत्सव', 'Shri Ram Navami Festival', 'ભગવાન શ્રી રામના જન્મોત્સવની ધામધૂમથી ઉજવણી. સવારે રામચરિતમાનસ પાઠ, બપોરે ભંડારા અને સાંજે ભવ્ય ઝાંકી.', NULL, NULL, '2026-04-25', '2026-04-25', '06:00:00', '22:00:00', 'Shree Pataliya Hanumanji Temple, Antarjal', NULL, '1', 'published', 'festival', NULL, '2026-03-31 14:31:36', '2026-03-31 14:31:36', NULL);
INSERT INTO \`temple_events\` (\`id\`, \`title_gu\`, \`title_hi\`, \`title_en\`, \`description_gu\`, \`description_hi\`, \`description_en\`, \`start_date\`, \`end_date\`, \`start_time\`, \`end_time\`, \`location\`, \`image_path\`, \`is_featured\`, \`status\`, \`event_type\`, \`created_by\`, \`created_at\`, \`updated_at\`, \`deleted_at\`) VALUES ('3', 'સાપ્તાહિક સુંદરકાંડ પાઠ', 'साप्ताहिक सुंदरकांड पाठ', 'Weekly Sundarkand Path', 'દર શનિવારે સાંજે ૫:૦૦ વાગ્યે સુંદરકાંડનો સામૂહિક પાઠ. તમામ ભક્તોને ભાગ લેવા વિનંતી.', NULL, NULL, '2026-04-04', NULL, '17:00:00', '19:30:00', 'Shree Pataliya Hanumanji Temple, Antarjal', NULL, '0', 'published', 'satsang', NULL, '2026-03-31 14:31:36', '2026-03-31 14:31:36', NULL);
INSERT INTO \`temple_events\` (\`id\`, \`title_gu\`, \`title_hi\`, \`title_en\`, \`description_gu\`, \`description_hi\`, \`description_en\`, \`start_date\`, \`end_date\`, \`start_time\`, \`end_time\`, \`location\`, \`image_path\`, \`is_featured\`, \`status\`, \`event_type\`, \`created_by\`, \`created_at\`, \`updated_at\`, \`deleted_at\`) VALUES ('4', 'દિવાળી મહોત્સવ', 'दिवाली महोत्सव', 'Diwali Festival', 'દિવાળી ના પાવન પ્રસંગે મંદિરમાં ભવ્ય દીપોત્સવ અને લક્ષ્મી પૂજા.', NULL, NULL, '2026-10-31', '2026-11-04', NULL, NULL, 'Shree Pataliya Hanumanji Temple, Antarjal', NULL, '1', 'published', 'festival', NULL, '2026-03-31 14:31:36', '2026-03-31 14:31:36', NULL);
INSERT INTO \`temple_announcements\` (\`id\`, \`title_gu\`, \`title_hi\`, \`title_en\`, \`body_gu\`, \`body_hi\`, \`body_en\`, \`image_path\`, \`is_urgent\`, \`published_at\`, \`expires_at\`, \`is_active\`, \`created_by\`, \`created_at\`, \`updated_at\`, \`deleted_at\`) VALUES ('1', 'હનુમાન જયંતિ મહોત્સવ — ૧૫ એપ્રિલ ૨૦૨૬', 'हनुमान जयंती महोत्सव — 15 अप्रैल 2026', 'Hanuman Jayanti Celebration — 15 April 2026', 'શ્રી પાતળિયા હનુમાનજી મંદિરમાં હનુમાન જયંતિનો ભવ્ય ઉત્સવ ઉજવવામાં આવશે. સવારે ૫:૦૦ વાગ્યાથી વિશેષ પૂજા અર્ચના શરૂ થશે. તમામ ભક્તોને ઉપસ્થિત રહેવા વિનંતી.', 'श्री पातळिया हनुमानजी मंदिर में हनुमान जयंती का भव्य उत्सव मनाया जाएगा।', NULL, NULL, '1', '2026-03-31 14:31:36', '2026-04-20 14:31:36', '1', NULL, '2026-03-31 14:31:36', '2026-03-31 14:31:36', NULL);
