INSERT INTO \`temple_product_categories\` (\`id\`, \`name_gu\`, \`name_hi\`, \`name_en\`, \`slug\`, \`description\`, \`image_path\`, \`sort_order\`, \`is_active\`, \`created_at\`, \`updated_at\`, \`deleted_at\`) VALUES ('3', 'પુસ્તકો', 'पुस्तकें', 'Religious Publications', 'religious-publications', 'ધાર્મિક પુસ્તકો, હનુમાન ચાલીસા, સુંદરકાંડ અને અન્ય આધ્યાત્મિક સાહિત્ય.', NULL, '3', '1', '2026-04-09 09:40:21', '2026-04-09 09:40:21', NULL);
