INSERT INTO \`temple_products\` (\`id\`, \`category_id\`, \`name_gu\`, \`name_hi\`, \`name_en\`, \`slug\`, \`description_gu\`, \`description_hi\`, \`description_en\`, \`price\`, \`stock_quantity\`, \`image_path\`, \`is_active\`, \`is_featured\`, \`is_seva_only\`, \`has_variants\`, \`variants\`, \`sort_order\`, \`created_at\`, \`updated_at\`, \`deleted_at\`) VALUES ('1', '1', 'શ્રી હનુમાનજી વસ્ત્ર - લાલ', 'श्री हनुमानजी वस्त्र - लाल', 'Red Hanuman Vastra', 'red-hanuman-vastra', 'શ્રી પાતળિયા હનુમાનજી મંદિરમાં ભગવાનને અર્પણ કરવા માટેનો લાલ રંગનો પવિત્ર વસ્ત્ર. શુદ્ધ કોટન કાપડમાંથી બનાવેલ, ઝરી બોર્ડર સાથે.', 'श्री पातलिया हनुमानजी मंदिर में भगवान को अर्पण करने के लिए लाल रंग का पवित्र वस्त्र. शुद्ध कॉटन कपड़े से बना, ज़री बॉर्डर के साथ.', 'Sacred red garment for offering to Hanumanji at Shree Pataliya Hanumanji Temple. Made from pure cotton fabric with zari border.', '1100.00', '25', NULL, '1', '1', '0', '0', NULL, '1', '2026-04-09 09:40:21', '2026-04-09 09:40:21', NULL);
INSERT INTO \`temple_products\` (\`id\`, \`category_id\`, \`name_gu\`, \`name_hi\`, \`name_en\`, \`slug\`, \`description_gu\`, \`description_hi\`, \`description_en\`, \`price\`, \`stock_quantity\`, \`image_path\`, \`is_active\`, \`is_featured\`, \`is_seva_only\`, \`has_variants\`, \`variants\`, \`sort_order\`, \`created_at\`, \`updated_at\`, \`deleted_at\`) VALUES ('2', '1', 'શ્રી હનુમાનજી વસ્ત્ર - કેસરી', 'श्री हनुमानजी वस्त्र - केसरी', 'Saffron Hanuman Vastra', 'saffron-hanuman-vastra', 'કેસરી રંગનો પવિત્ર વસ્ત્ર — હનુમાનજીનો પ્રિય રંગ. શુદ્ધ કોટન કાપડ, સુંદર ભરતકામ સાથે.', 'केसरी रंग का पवित्र वस्त्र — हनुमानजी का प्रिय रंग. शुद्ध कॉटन कपड़ा, सुंदर कढ़ाई के साथ.', 'Sacred saffron garment — Hanumanji\'s favourite colour. Pure cotton fabric with beautiful embroidery.', '1100.00', '13', NULL, '1', '1', '1', '0', NULL, '2', '2026-04-09 09:40:21', '2026-04-09 13:24:46', NULL);
INSERT INTO \`temple_products\` (\`id\`, \`category_id\`, \`name_gu\`, \`name_hi\`, \`name_en\`, \`slug\`, \`description_gu\`, \`description_hi\`, \`description_en\`, \`price\`, \`stock_quantity\`, \`image_path\`, \`is_active\`, \`is_featured\`, \`is_seva_only\`, \`has_variants\`, \`variants\`, \`sort_order\`, \`created_at\`, \`updated_at\`, \`deleted_at\`) VALUES ('3', '1', 'શ્રી હનુમાનજી શ્રૃંગાર વસ્ત્ર', 'श्री हनुमानजी श्रृंगार वस्त्र', 'Shringar Vastra Set', 'shringar-vastra-set', 'સંપૂર્ણ શ્રૃંગાર વસ્ત્ર સેટ — ઉત્તરીય, ધોતી અને પટકો સહિત. વિશેષ પ્રસંગોએ હનુમાનજીના શ્રૃંગાર માટે ઉપયોગી.', 'संपूर्ण श्रृंगार वस्त्र सेट — उत्तरीय, धोती और पटका सहित. विशेष अवसरों पर हनुमानजी के श्रृंगार के लिए उपयोगी.', 'Complete Shringar Vastra set including uttariya, dhoti and patka. Ideal for special occasion adornment of Hanumanji.', '2100.00', '13', NULL, '1', '0', '0', '0', NULL, '3', '2026-04-09 09:40:21', '2026-04-09 09:40:21', NULL);
INSERT INTO \`temple_products\` (\`id\`, \`category_id\`, \`name_gu\`, \`name_hi\`, \`name_en\`, \`slug\`, \`description_gu\`, \`description_hi\`, \`description_en\`, \`price\`, \`stock_quantity\`, \`image_path\`, \`is_active\`, \`is_featured\`, \`is_seva_only\`, \`has_variants\`, \`variants\`, \`sort_order\`, \`created_at\`, \`updated_at\`, \`deleted_at\`) VALUES ('4', '1', 'મુકુટ અને વસ્ત્ર સેટ', 'मुकुट और वस्त्र सेट', 'Mukut and Vastra Set', 'mukut-and-vastra-set', 'સુંદર મુકુટ સાથે મેચિંગ વસ્ત્ર સેટ. ઝરી અને ભરતકામથી સુશોભિત, મંદિરના મહોત્સવો માટે ઉત્તમ.', 'सुंदर मुकुट के साथ मैचिंग वस्त्र सेट. ज़री और कढ़ाई से सुशोभित, मंदिर के महोत्सवों के लिए उत्तम.', 'Beautiful crown with matching vastra set. Adorned with zari and embroidery, perfect for temple festivals.', '3500.00', '20', NULL, '1', '0', '0', '0', NULL, '4', '2026-04-09 09:40:21', '2026-04-09 09:40:21', NULL);
INSERT INTO \`temple_products\` (\`id\`, \`category_id\`, \`name_gu\`, \`name_hi\`, \`name_en\`, \`slug\`, \`description_gu\`, \`description_hi\`, \`description_en\`, \`price\`, \`stock_quantity\`, \`image_path\`, \`is_active\`, \`is_featured\`, \`is_seva_only\`, \`has_variants\`, \`variants\`, \`sort_order\`, \`created_at\`, \`updated_at\`, \`deleted_at\`) VALUES ('5', '1', 'ચાંદીનો વસ્ત્ર સેટ', 'चांदी का वस्त्र सेट', 'Silver Thread Vastra Set', 'silver-thread-vastra-set', 'ચાંદીના તારથી વણેલ પ્રિમિયમ વસ્ત્ર સેટ. ભગવાનના વિશેષ શ્રૃંગાર માટે — દિવાળી, જન્મોત્સવ જેવા મહાપર્વો માટે.', 'चांदी के तार से बुना प्रीमियम वस्त्र सेट. भगवान के विशेष श्रृंगार के लिए — दीवाली, जन्मोत्सव जैसे महापर्वों के लिए.', 'Premium vastra set woven with silver thread. For special adornment of the deity — ideal for Diwali, Janmotsav and other grand festivals.', '4000.00', '10', NULL, '1', '0', '0', '0', NULL, '5', '2026-04-09 09:40:21', '2026-04-09 09:40:21', NULL);
INSERT INTO \`temple_products\` (\`id\`, \`category_id\`, \`name_gu\`, \`name_hi\`, \`name_en\`, \`slug\`, \`description_gu\`, \`description_hi\`, \`description_en\`, \`price\`, \`stock_quantity\`, \`image_path\`, \`is_active\`, \`is_featured\`, \`is_seva_only\`, \`has_variants\`, \`variants\`, \`sort_order\`, \`created_at\`, \`updated_at\`, \`deleted_at\`) VALUES ('6', '1', 'ધોતી-ઉપરણો સેટ', 'धोती-उपरना सेट', 'Dhoti Uparna Set', 'dhoti-uparna-set', 'શુદ્ધ સફેદ ધોતી અને ઉપરણો — મંદિરના દૈનિક શ્રૃંગાર માટે. નરમ કોટન કાપડ, કેસરી બોર્ડર સાથે.', 'शुद्ध सफ़ेद धोती और उपरना — मंदिर के दैनिक श्रृंगार के लिए. नरम कॉटन कपड़ा, केसरी बॉर्डर के साथ.', 'Pure white dhoti and uparna for daily temple adornment. Soft cotton fabric with saffron border.', '1500.00', '20', NULL, '1', '0', '0', '0', NULL, '6', '2026-04-09 09:40:21', '2026-04-09 09:40:21', NULL);
INSERT INTO \`temple_products\` (\`id\`, \`category_id\`, \`name_gu\`, \`name_hi\`, \`name_en\`, \`slug\`, \`description_gu\`, \`description_hi\`, \`description_en\`, \`price\`, \`stock_quantity\`, \`image_path\`, \`is_active\`, \`is_featured\`, \`is_seva_only\`, \`has_variants\`, \`variants\`, \`sort_order\`, \`created_at\`, \`updated_at\`, \`deleted_at\`) VALUES ('7', '1', 'પટકો અને દુપટ્ટો', 'पटका और दुपट्टा', 'Patko and Dupatta', 'patko-and-dupatta', 'ભગવાનના કમર પર બાંધવાનો પટકો અને ખભા પર રાખવાનો દુપટ્ટો. સુંદર રંગ સંયોજન અને ઝરી કામ.', 'भगवान की कमर पर बांधने का पटका और कंधे पर रखने का दुपट्टा. सुंदर रंग संयोजन और ज़री काम.', 'Patko for the deity\'s waist and dupatta for the shoulders. Beautiful colour combination with zari work.', '1200.00', '26', NULL, '1', '0', '0', '0', NULL, '7', '2026-04-09 09:40:21', '2026-04-09 09:40:21', NULL);
INSERT INTO \`temple_products\` (\`id\`, \`category_id\`, \`name_gu\`, \`name_hi\`, \`name_en\`, \`slug\`, \`description_gu\`, \`description_hi\`, \`description_en\`, \`price\`, \`stock_quantity\`, \`image_path\`, \`is_active\`, \`is_featured\`, \`is_seva_only\`, \`has_variants\`, \`variants\`, \`sort_order\`, \`created_at\`, \`updated_at\`, \`deleted_at\`) VALUES ('8', '1', 'ફૂલોનો વસ્ત્ર હાર', 'फूलों का वस्त्र हार', 'Floral Vastra Garland', 'floral-vastra-garland', 'ફૂલોના આકારમાં કાપડથી બનાવેલ સુંદર હાર. લાંબા સમય સુધી ટકે છે, રોજિંદા શ્રૃંગાર માટે ઉત્તમ.', 'फूलों के आकार में कपड़े से बनी सुंदर माला. लंबे समय तक टिकती है, दैनिक श्रृंगार के लिए उत्तम.', 'Beautiful garland made from fabric in floral patterns. Long-lasting, perfect for daily adornment.', '1800.00', '38', NULL, '1', '0', '0', '0', NULL, '8', '2026-04-09 09:40:21', '2026-04-09 09:40:21', NULL);
INSERT INTO \`temple_products\` (\`id\`, \`category_id\`, \`name_gu\`, \`name_hi\`, \`name_en\`, \`slug\`, \`description_gu\`, \`description_hi\`, \`description_en\`, \`price\`, \`stock_quantity\`, \`image_path\`, \`is_active\`, \`is_featured\`, \`is_seva_only\`, \`has_variants\`, \`variants\`, \`sort_order\`, \`created_at\`, \`updated_at\`, \`deleted_at\`) VALUES ('9', '1', 'શિયાળુ ઊનનો વસ્ત્ર', 'शीतकालीन ऊनी वस्त्र', 'Winter Woolen Vastra', 'winter-woolen-vastra', 'શિયાળાની ઋતુ માટે ઊનનો ગરમ વસ્ત્ર. નરમ ઊન, કેસરી રંગ, ભરતકામ સાથે. ભગવાનને ઠંડીમાં ગરમાવો આપવા.', 'सर्दियों के मौसम के लिए ऊनी गर्म वस्त्र. नरम ऊन, केसरी रंग, कढ़ाई के साथ. भगवान को ठंड में गर्माहट देने के लिए.', 'Warm woolen vastra for the winter season. Soft wool, saffron colour, with embroidery. To keep the deity warm during cold months.', '2500.00', '19', NULL, '1', '0', '0', '0', NULL, '9', '2026-04-09 09:40:21', '2026-04-09 09:40:21', NULL);
INSERT INTO \`temple_products\` (\`id\`, \`category_id\`, \`name_gu\`, \`name_hi\`, \`name_en\`, \`slug\`, \`description_gu\`, \`description_hi\`, \`description_en\`, \`price\`, \`stock_quantity\`, \`image_path\`, \`is_active\`, \`is_featured\`, \`is_seva_only\`, \`has_variants\`, \`variants\`, \`sort_order\`, \`created_at\`, \`updated_at\`, \`deleted_at\`) VALUES ('10', '1', 'દિવાળી વિશેષ વસ્ત્ર', 'दीवाली विशेष वस्त्र', 'Diwali Special Vastra', 'diwali-special-vastra', 'દિવાળીના પાવન પર્વ માટે વિશેષ વસ્ત્ર. ભારે ઝરી કામ, મોતી અને કુંદનથી સજાવેલ. સીમિત માત્રામાં ઉપલબ્ધ.', 'दीवाली के पावन पर्व के लिए विशेष वस्त्र. भारी ज़री काम, मोती और कुंदन से सजाया हुआ. सीमित मात्रा में उपलब्ध.', 'Special vastra for the auspicious festival of Diwali. Heavy zari work, decorated with pearls and kundan. Available in limited quantity.', '3000.00', '29', NULL, '1', '1', '0', '0', NULL, '10', '2026-04-09 09:40:21', '2026-04-09 09:49:48', NULL);
INSERT INTO \`temple_products\` (\`id\`, \`category_id\`, \`name_gu\`, \`name_hi\`, \`name_en\`, \`slug\`, \`description_gu\`, \`description_hi\`, \`description_en\`, \`price\`, \`stock_quantity\`, \`image_path\`, \`is_active\`, \`is_featured\`, \`is_seva_only\`, \`has_variants\`, \`variants\`, \`sort_order\`, \`created_at\`, \`updated_at\`, \`deleted_at\`) VALUES ('19', '3', 'હનુમાન ચાલીસા — સચિત્ર', 'हनुमान चालीसा — सचित्र', 'Hanuman Chalisa Illustrated', 'hanuman-chalisa-illustrated', 'સુંદર ચિત્રો સાથેનું હનુમાન ચાલીસા પુસ્તક. ગુજરાતી અર્થ અને ટીકા સહિત. શ્રી પાતળિયા હનુમાનજી મંદિર દ્વારા પ્રકાશિત.', 'सुंदर चित्रों के साथ हनुमान चालीसा पुस्तक. गुजराती अर्थ और टीका सहित. श्री पातलिया हनुमानजी मंदिर द्वारा प्रकाशित.', 'Hanuman Chalisa book with beautiful illustrations. Including Gujarati meaning and commentary. Published by Shree Pataliya Hanumanji Temple.', '151.00', '22', NULL, '1', '0', '0', '0', NULL, '1', '2026-04-09 09:40:21', '2026-04-09 09:40:21', NULL);
INSERT INTO \`temple_products\` (\`id\`, \`category_id\`, \`name_gu\`, \`name_hi\`, \`name_en\`, \`slug\`, \`description_gu\`, \`description_hi\`, \`description_en\`, \`price\`, \`stock_quantity\`, \`image_path\`, \`is_active\`, \`is_featured\`, \`is_seva_only\`, \`has_variants\`, \`variants\`, \`sort_order\`, \`created_at\`, \`updated_at\`, \`deleted_at\`) VALUES ('20', '3', 'સુંદરકાંડ — ગુજરાતી ટીકા', 'सुंदरकांड — गुजराती टीका', 'Sundarkand with Gujarati Commentary', 'sundarkand-with-gujarati-commentary', 'તુલસીદાસજી રચિત રામચરિતમાનસનો સુંદરકાંડ — વિસ્તૃત ગુજરાતી ટીકા સાથે. ભક્તોના દૈનિક પાઠ માટે ઉત્તમ.', 'तुलसीदासजी रचित रामचरितमानस का सुंदरकांड — विस्तृत गुजराती टीका के साथ. भक्तों के दैनिक पाठ के लिए उत्तम.', 'Sundarkand from Tulsidas\'s Ramcharitmanas — with detailed Gujarati commentary. Ideal for daily recitation by devotees.', '351.00', '39', NULL, '1', '0', '0', '0', NULL, '2', '2026-04-09 09:40:21', '2026-04-09 09:40:21', NULL);
INSERT INTO \`temple_products\` (\`id\`, \`category_id\`, \`name_gu\`, \`name_hi\`, \`name_en\`, \`slug\`, \`description_gu\`, \`description_hi\`, \`description_en\`, \`price\`, \`stock_quantity\`, \`image_path\`, \`is_active\`, \`is_featured\`, \`is_seva_only\`, \`has_variants\`, \`variants\`, \`sort_order\`, \`created_at\`, \`updated_at\`, \`deleted_at\`) VALUES ('21', '3', 'શ્રી રામચરિતમાનસ', 'श्री रामचरितमानस', 'Shri Ramcharitmanas', 'shri-ramcharitmanas', 'ગોસ્વામી તુલસીદાસજી રચિત સંપૂર્ણ રામચરિતમાનસ. ગુજરાતી અનુવાદ અને ટીકા સહિત. મોટા અક્ષરોમાં છાપેલ.', 'गोस्वामी तुलसीदासजी रचित संपूर्ण रामचरितमानस. गुजराती अनुवाद और टीका सहित. बड़े अक्षरों में छपा हुआ.', 'Complete Ramcharitmanas by Goswami Tulsidas. With Gujarati translation and commentary. Printed in large font.', '551.00', '14', NULL, '1', '1', '0', '0', NULL, '3', '2026-04-09 09:40:21', '2026-04-09 09:40:21', NULL);
INSERT INTO \`temple_products\` (\`id\`, \`category_id\`, \`name_gu\`, \`name_hi\`, \`name_en\`, \`slug\`, \`description_gu\`, \`description_hi\`, \`description_en\`, \`price\`, \`stock_quantity\`, \`image_path\`, \`is_active\`, \`is_featured\`, \`is_seva_only\`, \`has_variants\`, \`variants\`, \`sort_order\`, \`created_at\`, \`updated_at\`, \`deleted_at\`) VALUES ('22', '3', 'બજરંગ બાણ અને આરતી સંગ્રહ', 'बजरंग बाण और आरती संग्रह', 'Bajrang Baan and Aarti Collection', 'bajrang-baan-and-aarti-collection', 'બજરંગ બાણ, હનુમાન ચાલીસા, આરતી અને સ્તુતિનો સંગ્રહ — એક જ પુસ્તકમાં. પોકેટ સાઈઝ, મુસાફરીમાં લઈ જવા યોગ્ય.', 'बजरंग बाण, हनुमान चालीसा, आरती और स्तुति का संग्रह — एक ही पुस्तक में. पॉकेट साइज़, यात्रा में ले जाने योग्य.', 'Collection of Bajrang Baan, Hanuman Chalisa, aarti and stuti — all in one book. Pocket size, convenient for travel.', '199.00', '19', NULL, '1', '0', '0', '0', NULL, '4', '2026-04-09 09:40:21', '2026-04-09 09:40:21', NULL);
INSERT INTO \`temple_products\` (\`id\`, \`category_id\`, \`name_gu\`, \`name_hi\`, \`name_en\`, \`slug\`, \`description_gu\`, \`description_hi\`, \`description_en\`, \`price\`, \`stock_quantity\`, \`image_path\`, \`is_active\`, \`is_featured\`, \`is_seva_only\`, \`has_variants\`, \`variants\`, \`sort_order\`, \`created_at\`, \`updated_at\`, \`deleted_at\`) VALUES ('23', '3', 'હનુમાન કથા — બાળકો માટે', 'हनुमान कथा — बच्चों के लिए', 'Hanuman Stories for Children', 'hanuman-stories-for-children', 'બાળકો માટે સરળ ભાષામાં હનુમાનજીની કથાઓ. રંગબેરંગી ચિત્રો સાથે. બાળકોને સંસ્કાર અને ભક્તિ શીખવતું પુસ્તક.', 'बच्चों के लिए सरल भाषा में हनुमानजी की कथाएं. रंग-बिरंगे चित्रों के साथ. बच्चों को संस्कार और भक्ति सिखाती पुस्तक.', 'Stories of Hanumanji in simple language for children. With colourful illustrations. A book that teaches children values and devotion.', '249.00', '43', NULL, '1', '0', '0', '0', NULL, '5', '2026-04-09 09:40:21', '2026-04-09 09:40:21', NULL);
INSERT INTO \`temple_products\` (\`id\`, \`category_id\`, \`name_gu\`, \`name_hi\`, \`name_en\`, \`slug\`, \`description_gu\`, \`description_hi\`, \`description_en\`, \`price\`, \`stock_quantity\`, \`image_path\`, \`is_active\`, \`is_featured\`, \`is_seva_only\`, \`has_variants\`, \`variants\`, \`sort_order\`, \`created_at\`, \`updated_at\`, \`deleted_at\`) VALUES ('24', '4', 'રુદ્રાક્ષ માળા', 'रुद्राक्ष माला', 'Rudraksha Mala', 'rudraksha-mala', 'અસલ 5-મુખી રુદ્રાક્ષ માળા — 108 દાણા. મંદિરમાં અભિમંત્રિત. જાપ અને ધ્યાન માટે ઉત્તમ.', 'असली 5-मुखी रुद्राक्ष माला — 108 दाने. मंदिर में अभिमंत्रित. जाप और ध्यान के लिए उत्तम.', 'Authentic 5-mukhi Rudraksha mala — 108 beads. Energised at the temple. Ideal for chanting and meditation.', '599.00', '44', NULL, '1', '0', '0', '0', NULL, '1', '2026-04-09 09:40:21', '2026-04-09 09:40:21', NULL);
INSERT INTO \`temple_products\` (\`id\`, \`category_id\`, \`name_gu\`, \`name_hi\`, \`name_en\`, \`slug\`, \`description_gu\`, \`description_hi\`, \`description_en\`, \`price\`, \`stock_quantity\`, \`image_path\`, \`is_active\`, \`is_featured\`, \`is_seva_only\`, \`has_variants\`, \`variants\`, \`sort_order\`, \`created_at\`, \`updated_at\`, \`deleted_at\`) VALUES ('25', '4', 'ચંદન માળા', 'चंदन माला', 'Sandalwood Mala', 'sandalwood-mala', 'શુદ્ધ ચંદનની સુગંધિત માળા — 108 દાણા. મંદિરમાં અભિમંત્રિત. ચંદનની કુદરતી સુગંધ, શાંતિ અને ધ્યાન માટે.', 'शुद्ध चंदन की सुगंधित माला — 108 दाने. मंदिर में अभिमंत्रित. चंदन की प्राकृतिक सुगंध, शांति और ध्यान के लिए.', 'Pure sandalwood fragrant mala — 108 beads. Energised at the temple. Natural sandalwood fragrance, for peace and meditation.', '899.00', '27', NULL, '1', '0', '0', '0', NULL, '2', '2026-04-09 09:40:21', '2026-04-09 09:40:21', NULL);
INSERT INTO \`temple_products\` (\`id\`, \`category_id\`, \`name_gu\`, \`name_hi\`, \`name_en\`, \`slug\`, \`description_gu\`, \`description_hi\`, \`description_en\`, \`price\`, \`stock_quantity\`, \`image_path\`, \`is_active\`, \`is_featured\`, \`is_seva_only\`, \`has_variants\`, \`variants\`, \`sort_order\`, \`created_at\`, \`updated_at\`, \`deleted_at\`) VALUES ('26', '4', 'તુલસી માળા', 'तुलसी माला', 'Tulsi Mala', 'tulsi-mala', 'પવિત્ર તુલસીની માળા — 108 દાણા. મંદિરમાં અભિમંત્રિત. રામ નામ જાપ અને દૈનિક પૂજા માટે.', 'पवित्र तुलसी की माला — 108 दाने. मंदिर में अभिमंत्रित. राम नाम जाप और दैनिक पूजा के लिए.', 'Sacred Tulsi mala — 108 beads. Energised at the temple. For Ram naam chanting and daily worship.', '299.00', '43', NULL, '1', '0', '0', '0', NULL, '3', '2026-04-09 09:40:21', '2026-04-09 09:40:21', NULL);
INSERT INTO \`temple_products\` (\`id\`, \`category_id\`, \`name_gu\`, \`name_hi\`, \`name_en\`, \`slug\`, \`description_gu\`, \`description_hi\`, \`description_en\`, \`price\`, \`stock_quantity\`, \`image_path\`, \`is_active\`, \`is_featured\`, \`is_seva_only\`, \`has_variants\`, \`variants\`, \`sort_order\`, \`created_at\`, \`updated_at\`, \`deleted_at\`) VALUES ('27', '4', 'શ્રી હનુમાનજી ફોટો ફ્રેમ — નાનો', 'श्री हनुमानजी फोटो फ्रेम — छोटा', 'Hanumanji Photo Frame Small', 'hanumanji-photo-frame-small', 'શ્રી પાતળિયા હનુમાનજીની મૂર્તિનો સુંદર ફોટો ફ્રેમ — 6×8 ઈંચ. ઘર અને ઓફિસમાં મૂકવા માટે, ગોલ્ડ કલરની ફ્રેમ.', 'श्री पातलिया हनुमानजी की मूर्ति का सुंदर फोटो फ्रेम — 6×8 इंच. घर और ऑफिस में रखने के लिए, गोल्ड कलर की फ्रेम.', 'Beautiful photo frame of Shree Pataliya Hanumanji\'s murti — 6x8 inches. For home and office display, gold coloured frame.', '399.00', '34', NULL, '1', '0', '0', '0', NULL, '4', '2026-04-09 09:40:21', '2026-04-09 09:40:21', NULL);
INSERT INTO \`temple_products\` (\`id\`, \`category_id\`, \`name_gu\`, \`name_hi\`, \`name_en\`, \`slug\`, \`description_gu\`, \`description_hi\`, \`description_en\`, \`price\`, \`stock_quantity\`, \`image_path\`, \`is_active\`, \`is_featured\`, \`is_seva_only\`, \`has_variants\`, \`variants\`, \`sort_order\`, \`created_at\`, \`updated_at\`, \`deleted_at\`) VALUES ('28', '4', 'શ્રી હનુમાનજી ફોટો ફ્રેમ — મોટો', 'श्री हनुमानजी फोटो फ्रेम — बड़ा', 'Hanumanji Photo Frame Large', 'hanumanji-photo-frame-large', 'શ્રી પાતળિયા હનુમાનજીની મૂર્તિનો મોટો ફોટો ફ્રેમ — 12×16 ઈંચ. પૂજા ઘર માટે ઉત્તમ, પ્રિમિયમ વૂડન ફ્રેમ.', 'श्री पातलिया हनुमानजी की मूर्ति का बड़ा फोटो फ्रेम — 12×16 इंच. पूजा घर के लिए उत्तम, प्रीमियम वुडन फ्रेम.', 'Large photo frame of Shree Pataliya Hanumanji\'s murti — 12x16 inches. Ideal for prayer room, premium wooden frame.', '799.00', '10', NULL, '1', '0', '0', '0', NULL, '5', '2026-04-09 09:40:21', '2026-04-09 09:40:21', NULL);
INSERT INTO \`temple_products\` (\`id\`, \`category_id\`, \`name_gu\`, \`name_hi\`, \`name_en\`, \`slug\`, \`description_gu\`, \`description_hi\`, \`description_en\`, \`price\`, \`stock_quantity\`, \`image_path\`, \`is_active\`, \`is_featured\`, \`is_seva_only\`, \`has_variants\`, \`variants\`, \`sort_order\`, \`created_at\`, \`updated_at\`, \`deleted_at\`) VALUES ('29', '4', 'ગદા કીચેન — પિત્તળ', 'गदा कीचेन — पीतल', 'Brass Gada Keychain', 'brass-gada-keychain', 'હનુમાનજીની ગદાના આકારની પિત્તળની કીચેન. મંદિરની યાદગીરી, ભેટ આપવા માટે ઉત્તમ.', 'हनुमानजी की गदा के आकार की पीतल की कीचेन. मंदिर की याद, उपहार देने के लिए उत्तम.', 'Brass keychain in the shape of Hanumanji\'s gada. A temple souvenir, perfect as a gift.', '149.00', '19', NULL, '1', '0', '0', '0', NULL, '6', '2026-04-09 09:40:21', '2026-04-09 09:40:21', NULL);
INSERT INTO \`temple_products\` (\`id\`, \`category_id\`, \`name_gu\`, \`name_hi\`, \`name_en\`, \`slug\`, \`description_gu\`, \`description_hi\`, \`description_en\`, \`price\`, \`stock_quantity\`, \`image_path\`, \`is_active\`, \`is_featured\`, \`is_seva_only\`, \`has_variants\`, \`variants\`, \`sort_order\`, \`created_at\`, \`updated_at\`, \`deleted_at\`) VALUES ('30', '4', 'ઓર્ગેનિક જ્યૂટ શોપિંગ બેગ', 'ऑर्गेनिक जूट शॉपिंग बैग', 'Organic Jute Shopping Bag', 'organic-jute-shopping-bag', 'મંદિરના લોગો અને હનુમાનજીની છબી સાથેની જ્યૂટ શોપિંગ બેગ. પર્યાવરણ-મૈત્રીપૂર્ણ, રોજિંદા ઉપયોગ માટે મજબૂત.', 'मंदिर के लोगो और हनुमानजी की छवि के साथ जूट शॉपिंग बैग. पर्यावरण-अनुकूल, दैनिक उपयोग के लिए मजबूत.', 'Jute shopping bag with temple logo and Hanumanji\'s image. Eco-friendly, sturdy for daily use.', '249.00', '10', NULL, '1', '0', '0', '0', NULL, '7', '2026-04-09 09:40:21', '2026-04-09 09:40:21', NULL);
INSERT INTO \`temple_products\` (\`id\`, \`category_id\`, \`name_gu\`, \`name_hi\`, \`name_en\`, \`slug\`, \`description_gu\`, \`description_hi\`, \`description_en\`, \`price\`, \`stock_quantity\`, \`image_path\`, \`is_active\`, \`is_featured\`, \`is_seva_only\`, \`has_variants\`, \`variants\`, \`sort_order\`, \`created_at\`, \`updated_at\`, \`deleted_at\`) VALUES ('31', '2', 'હનુમાનજી પેંડા પ્રસાદ', 'हनुमानजी पेड़ा प्रसाद', 'Hanumanji Peda Prasad', 'hanumanji-peda-prasad', 'શ્રી પાતળિયા હનુમાનજી મંદિરના પવિત્ર પેંડા પ્રસાદ. શુદ્ધ ઘીમાં બનાવેલ, મંદિરમાં અર્પણ કરાયેલ.', 'श्री पातलिया हनुमानजी मंदिर का पवित्र पेड़ा प्रसाद. शुद्ध घी में बना, मंदिर में अर्पित.', 'Sacred Peda Prasad from Shree Pataliya Hanumanji Temple. Made with pure ghee, offered at the temple.', '199.00', '48', NULL, '1', '1', '0', '1', '[{\"label\": \"250 ગ્રામ\", \"price\": 199}, {\"label\": \"500 ગ્રામ\", \"price\": 349}, {\"label\": \"1 કિલો\", \"price\": 649}]', '1', '2026-04-09 15:44:37', '2026-04-09 14:01:36', NULL);
INSERT INTO \`temple_products\` (\`id\`, \`category_id\`, \`name_gu\`, \`name_hi\`, \`name_en\`, \`slug\`, \`description_gu\`, \`description_hi\`, \`description_en\`, \`price\`, \`stock_quantity\`, \`image_path\`, \`is_active\`, \`is_featured\`, \`is_seva_only\`, \`has_variants\`, \`variants\`, \`sort_order\`, \`created_at\`, \`updated_at\`, \`deleted_at\`) VALUES ('32', '2', 'શ્રી લાડુ પ્રસાદ', 'श्री लड्डू प्रसाद', 'Shri Ladoo Prasad', 'shri-ladoo-prasad', 'શ્રી હનુમાનજીને પ્રિય લાડુ પ્રસાદ. દેશી ઘી અને ગોળમાં બનાવેલ પારંપરિક રેસિપી.', 'श्री हनुमानजी को प्रिय लड्डू प्रसाद. देसी घी और गुड़ में बनी पारंपरिक रेसिपी.', 'Ladoo Prasad dear to Shri Hanumanji. Traditional recipe made with desi ghee and jaggery.', '249.00', '39', NULL, '1', '0', '0', '1', '[{\"label\": \"250 ગ્રામ\", \"price\": 249}, {\"label\": \"500 ગ્રામ\", \"price\": 449}, {\"label\": \"1 કિલો\", \"price\": 799}]', '2', '2026-04-09 15:44:37', '2026-04-09 14:01:36', NULL);
INSERT INTO \`temple_products\` (\`id\`, \`category_id\`, \`name_gu\`, \`name_hi\`, \`name_en\`, \`slug\`, \`description_gu\`, \`description_hi\`, \`description_en\`, \`price\`, \`stock_quantity\`, \`image_path\`, \`is_active\`, \`is_featured\`, \`is_seva_only\`, \`has_variants\`, \`variants\`, \`sort_order\`, \`created_at\`, \`updated_at\`, \`deleted_at\`) VALUES ('33', '2', 'મિક્સ મીઠાઈ બોક્સ', 'मिक्स मिठाई बॉक्स', 'Mixed Sweet Box', 'mixed-sweet-box', 'વિવિધ મીઠાઈઓનું મિક્સ બોક્સ — પેંડા, લાડુ, બરફી. શુભ પ્રસંગો અને તહેવારો માટે ઉત્તમ.', 'विविध मिठाइयों का मिक्स बॉक्स — पेड़ा, लड्डू, बर्फी. शुभ अवसरों और त्योहारों के लिए उत्तम.', 'Mixed sweet box — Peda, Ladoo, Barfi. Perfect for auspicious occasions and festivals.', '899.00', '30', NULL, '1', '0', '0', '1', '[{\"label\": \"1 કિલો\", \"price\": 899}, {\"label\": \"2 કિલો\", \"price\": 1699}]', '3', '2026-04-09 15:44:37', '2026-04-09 15:44:37', NULL);
INSERT INTO \`temple_products\` (\`id\`, \`category_id\`, \`name_gu\`, \`name_hi\`, \`name_en\`, \`slug\`, \`description_gu\`, \`description_hi\`, \`description_en\`, \`price\`, \`stock_quantity\`, \`image_path\`, \`is_active\`, \`is_featured\`, \`is_seva_only\`, \`has_variants\`, \`variants\`, \`sort_order\`, \`created_at\`, \`updated_at\`, \`deleted_at\`) VALUES ('34', '2', 'હનુમાનજી પેંડા - 250 ગ્રામ', 'हनुमानजी पेड़ा - 250 ग्राम', 'Peda Box 250gm', 'peda-box-250gm', 'શ્રી પાતળિયા હનુમાનજી મંદિરના પવિત્ર પેંડા પ્રસાદ. શુદ્ધ ઘી અને ખાંડથી બનાવેલ, 250 ગ્રામ પેકિંગ.', 'श्री पातलिया हनुमानजी मंदिर का पवित्र पेड़ा प्रसाद. शुद्ध घी और चीनी से बना, 250 ग्राम पैकिंग.', 'Sacred peda prasad from Shree Pataliya Hanumanji Temple. Made with pure ghee and sugar, 250gm packing.', '199.00', '22', NULL, '1', '0', '0', '0', NULL, '1', '2026-04-10 14:18:31', '2026-04-10 14:18:31', NULL);
