INSERT INTO \`temple_products\` (\`id\`, \`category_id\`, \`name_gu\`, \`name_hi\`, \`name_en\`, \`slug\`, \`description_gu\`, \`description_hi\`, \`description_en\`, \`price\`, \`stock_quantity\`, \`image_path\`, \`is_active\`, \`is_featured\`, \`is_seva_only\`, \`has_variants\`, \`variants\`, \`sort_order\`, \`created_at\`, \`updated_at\`, \`deleted_at\`) VALUES ('40', '2', 'મિક્સ મીઠાઈ બોક્સ - 1 કિલો', 'मिक्स मिठाई बॉक्स - 1 किलो', 'Mixed Sweet Box 1kg', 'mixed-sweet-box-1kg', 'પેંડા, લાડુ, બરફી અને મોહનથાળ — ચાર પ્રકારની મીઠાઈનું મિક્સ બોક્સ. મંદિરના પવિત્ર પ્રસાદ, 1 કિલો ગિફ્ટ પેકિંગ.', 'पेड़ा, लड्डू, बर्फी और मोहनथाल — चार प्रकार की मिठाई का मिक्स बॉक्स. मंदिर का पवित्र प्रसाद, 1 किलो गिफ्ट पैकिंग.', 'Peda, ladoo, barfi and mohanthal — a mixed box of four types of sweets. Sacred temple prasad, 1kg gift packing.', '899.00', '15', NULL, '1', '0', '0', '0', NULL, '7', '2026-04-10 14:18:31', '2026-04-10 14:18:31', NULL);
INSERT INTO \`temple_products\` (\`id\`, \`category_id\`, \`name_gu\`, \`name_hi\`, \`name_en\`, \`slug\`, \`description_gu\`, \`description_hi\`, \`description_en\`, \`price\`, \`stock_quantity\`, \`image_path\`, \`is_active\`, \`is_featured\`, \`is_seva_only\`, \`has_variants\`, \`variants\`, \`sort_order\`, \`created_at\`, \`updated_at\`, \`deleted_at\`) VALUES ('41', '2', 'મિક્સ મીઠાઈ બોક્સ - 2 કિલો', 'मिक्स मिठाई बॉक्स - 2 किलो', 'Mixed Sweet Box 2kg', 'mixed-sweet-box-2kg', 'પેંડા, લાડુ, બરફી અને મોહનથાળ — ચાર પ્રકારની મીઠાઈનું મોટું મિક્સ બોક્સ. તહેવારો અને પ્રસંગો માટે, 2 કિલો પ્રિમિયમ ગિફ્ટ પેકિંગ.', 'पेड़ा, लड्डू, बर्फी और मोहनथाल — चार प्रकार की मिठाई का बड़ा मिक्स बॉक्स. त्योहारों और अवसरों के लिए, 2 किलो प्रीमियम गिफ्ट पैकिंग.', 'Peda, ladoo, barfi and mohanthal — a large mixed box of four types of sweets. For festivals and occasions, 2kg premium gift packing.', '1699.00', '19', NULL, '1', '0', '0', '0', NULL, '8', '2026-04-10 14:18:31', '2026-04-10 14:18:31', NULL);
INSERT INTO \`temple_blog_posts\` (\`id\`, \`slug\`, \`title_gu\`, \`title_hi\`, \`title_en\`, \`body_gu\`, \`body_hi\`, \`body_en\`, \`excerpt_gu\`, \`featured_image_path\`, \`meta_title\`, \`meta_description\`, \`category\`, \`status\`, \`published_at\`, \`created_by\`, \`created_at\`, \`updated_at\`, \`deleted_at\`) VALUES ('1', 'hanuman-chalisa-mahatmya', 'હનુમાન ચાલીસાનું મહાત્મ્ય', 'हनुमान चालीसा का महात्म्य', 'Significance of Hanuman Chalisa', '<p>હનુમાન ચાલીસા ગોસ્વામી તુલસીદાસજી રચિત એક મહાન સ્તોત્ર છે. ચાલીસ ચોપાઈઓ ધરાવતું આ સ્તોત્ર હનુમાનજીના ગુણો, લીલાઓ અને પરાક્રમોનું વર્ણન કરે છે.</p><p>દૈનિક હનુમાન ચાલીસાના પાઠથી ભય, રોગ અને દુઃખોનો નાશ થાય છે. શનિવારે અને મંગળવારે હનુમાન ચાલીસાનો પાઠ વિશેષ ફળદાયી માનવામાં આવે છે.</p>', '<p>हनुमान चालीसा गोस्वामी तुलसीदासजी रचित एक महान स्तोत्र है।</p>', NULL, 'હનુમાન ચાલીસા ગોસ્વામી તુલસીદાસજી રચિત એક મહાન સ્તોત્ર છે. દૈનિક પાઠનું મહત્વ જાણો.', NULL, NULL, NULL, 'spiritual', 'published', '2026-03-26 14:31:36', NULL, '2026-03-31 14:31:36', '2026-03-31 14:31:36', NULL);
INSERT INTO \`temple_blog_posts\` (\`id\`, \`slug\`, \`title_gu\`, \`title_hi\`, \`title_en\`, \`body_gu\`, \`body_hi\`, \`body_en\`, \`excerpt_gu\`, \`featured_image_path\`, \`meta_title\`, \`meta_description\`, \`category\`, \`status\`, \`published_at\`, \`created_by\`, \`created_at\`, \`updated_at\`, \`deleted_at\`) VALUES ('2', 'mandir-itihas', 'શ્રી પાતળિયા હનુમાનજી મંદિરનો ઇતિહાસ', 'श्री पातळिया हनुमानजी मंदिर का इतिहास', 'History of Shree Pataliya Hanumanji Temple', '<p>અંતરજાલ, ગાંધીધામ, કચ્છમાં આવેલું શ્રી પાતળિયા હનુમાનજી મંદિર ભક્તોની આસ્થાનું કેન્દ્ર છે. મંદિરની સ્થાપના ઘણા દાયકાઓ પહેલા થઈ હતી.</p><p>ટ્રસ્ટ દ્વારા મંદિરના સતત વિકાસ અને ભક્તોની સેવા-સુશ્રુષા કરવામાં આવી રહી છે.</p>', NULL, NULL, 'શ્રી પાતળિયા હનુમાનજી મંદિરના ઇતિહાસ અને પરંપરા વિશે જાણો.', NULL, NULL, NULL, 'general', 'published', '2026-03-19 14:31:36', NULL, '2026-03-31 14:31:36', '2026-03-31 14:31:36', NULL);
INSERT INTO \`temple_blog_posts\` (\`id\`, \`slug\`, \`title_gu\`, \`title_hi\`, \`title_en\`, \`body_gu\`, \`body_hi\`, \`body_en\`, \`excerpt_gu\`, \`featured_image_path\`, \`meta_title\`, \`meta_description\`, \`category\`, \`status\`, \`published_at\`, \`created_by\`, \`created_at\`, \`updated_at\`, \`deleted_at\`) VALUES ('3', 'shravan-mas-mahatva', 'શ્રાવણ માસનું મહત્વ', 'श्रावण मास का महत्व', 'Significance of Shravan Month', '<p>શ્રાવણ માસ હિંદુ ધર્મમાં અત્યંત પવિત્ર માનવામાં આવે છે. આ માસમાં શિવજી અને હનુમાનજીની પૂજા વિશેષ ફળદાયી છે.</p>', NULL, NULL, 'શ્રાવણ માસની પવિત્રતા અને વ્રત-ત્યોહારો વિશે.', NULL, NULL, NULL, 'spiritual', 'published', '2026-03-11 14:31:36', NULL, '2026-03-31 14:31:36', '2026-03-31 14:31:36', NULL);
INSERT INTO \`temple_pages\` (\`id\`, \`slug\`, \`title_gu\`, \`title_hi\`, \`title_en\`, \`body_gu\`, \`body_hi\`, \`body_en\`, \`featured_image_path\`, \`meta_title\`, \`meta_description\`, \`parent_slug\`, \`sort_order\`, \`status\`, \`template\`, \`created_by\`, \`published_at\`, \`created_at\`, \`updated_at\`, \`deleted_at\`) VALUES ('1', 'parichay', 'પરિચય', 'परिचय', 'Introduction', '<p>શ્રી પાતળિયા હનુમાનજી સેવા ટ્રસ્ટ, અંતરજાલ, ગાંધીધામ, કચ્છ ખાતે આવેલું આ પવિત્ર મંદિર ભક્તોના શ્રદ્ધાનું કેન્દ્ર છે. મંદિરમાં હનુમાનજી મહારાજની ભવ્ય મૂર્તિ સ્થાપિત છે. દરરોજ સેંકડો ભક્તો દર્શન માટે આવે છે.</p>', '<p>श्री पातळिया हनुमानजी सेवा ट्रस्ट, अंतरजाल, गांधीधाम, कच्छ में स्थित यह पवित्र मंदिर भक्तों की श्रद्धा का केंद्र है। मंदिर में हनुमानजी महाराज की भव्य मूर्ति स्थापित है।</p>', '<p>Shree Pataliya Hanumanji Seva Trust temple, located in Antarjal, Gandhidham, Kutch, is a sacred center of devotion. The temple houses a grand idol of Hanumanji Maharaj and attracts hundreds of devotees daily.</p>', NULL, NULL, NULL, NULL, '1', 'published', 'default', NULL, '2026-03-31 14:31:36', '2026-03-31 14:31:36', '2026-03-31 14:31:36', NULL);
INSERT INTO \`temple_pages\` (\`id\`, \`slug\`, \`title_gu\`, \`title_hi\`, \`title_en\`, \`body_gu\`, \`body_hi\`, \`body_en\`, \`featured_image_path\`, \`meta_title\`, \`meta_description\`, \`parent_slug\`, \`sort_order\`, \`status\`, \`template\`, \`created_by\`, \`published_at\`, \`created_at\`, \`updated_at\`, \`deleted_at\`) VALUES ('2', 'itihas', 'ઇતિહાસ', 'इतिहास', 'History', '<p>શ્રી પાતળિયા હનુમાનજી મંદિરનો ઇતિહાસ ઘણો પ્રાચીન છે. આ મંદિર ભક્તોની આસ્થા અને શ્રદ્ધાનું પ્રતીક છે. વર્ષોથી ટ્રસ્ટી મંડળ મંદિરના વિકાસ અને જીર્ણોદ્ધાર માટે સતત કાર્યરત છે.</p>', '<p>श्री पातळिया हनुमानजी मंदिर का इतिहास बहुत प्राचीन है। यह मंदिर भक्तों की आस्था और श्रद्धा का प्रतीक है।</p>', '<p>The history of Shree Pataliya Hanumanji Temple is ancient. The temple stands as a symbol of devotion and faith. The trust committee has been continuously working towards the development and renovation of the temple.</p>', NULL, NULL, NULL, NULL, '2', 'published', 'default', NULL, '2026-03-31 14:31:36', '2026-03-31 14:31:36', '2026-03-31 14:31:36', NULL);
INSERT INTO \`temple_pages\` (\`id\`, \`slug\`, \`title_gu\`, \`title_hi\`, \`title_en\`, \`body_gu\`, \`body_hi\`, \`body_en\`, \`featured_image_path\`, \`meta_title\`, \`meta_description\`, \`parent_slug\`, \`sort_order\`, \`status\`, \`template\`, \`created_by\`, \`published_at\`, \`created_at\`, \`updated_at\`, \`deleted_at\`) VALUES ('3', 'mahima', 'મહિમા', 'महिमा', 'Glory', '<p>શ્રી પાતળિયા હનુમાનજી મંદિરની મહિમા અપરંપાર છે. અનેક ભક્તોએ અહીં દર્શન કરીને ચમત્કારિક અનુભવો કર્યા છે. હનુમાનજી મહારાજ ભક્તોની મનોકામના પૂર્ણ કરે છે.</p>', '<p>श्री पातळिया हनुमानजी मंदिर की महिमा अपरंपार है। अनेक भक्तों ने यहां दर्शन करके चमत्कारिक अनुभव किए हैं।</p>', '<p>The glory of Shree Pataliya Hanumanji Temple is immense. Many devotees have experienced miracles after visiting the temple. Hanumanji Maharaj fulfills the wishes of his devotees.</p>', NULL, NULL, NULL, NULL, '3', 'published', 'default', NULL, '2026-03-31 14:31:36', '2026-03-31 14:31:36', '2026-03-31 14:31:36', NULL);
INSERT INTO \`temple_donation_campaigns\` (\`id\`, \`title_gu\`, \`title_hi\`, \`title_en\`, \`slug\`, \`description_gu\`, \`description_hi\`, \`description_en\`, \`writeup_gu\`, \`writeup_hi\`, \`writeup_en\`, \`goal_amount\`, \`raised_amount\`, \`donor_count\`, \`image_path\`, \`media\`, \`faqs\`, \`start_date\`, \`end_date\`, \`is_active\`, \`show_donor_list\`, \`is_featured\`, \`created_at\`, \`updated_at\`, \`deleted_at\`) VALUES ('1', 'મંદિર જીર્ણોદ્ધાર અભિયાન', 'मंदिर जीर्णोद्धार अभियान', 'Temple Renovation Campaign', 'temple-renovation-campaign', 'શ્રી પાતળિયા હનુમાનજી મંદિરના જીર્ણોદ્ધાર માટે ભક્તોના સહયોગની જરૂર છે. ગર્ભગૃહ, સભા મંડપ અને પરિસરના નવીનીકરણ માટે આ અભિયાન ચાલી રહ્યું છે.', 'श्री पातळिया हनुमानजी मंदिर के जीर्णोद्धार के लिए भक्तों के सहयोग की आवश्यकता है।', NULL, NULL, NULL, NULL, '2500000.00', '875000.00', '156', NULL, NULL, NULL, '2026-01-31', '2026-10-01', '1', '1', '0', '2026-03-31 14:31:36', '2026-03-31 14:31:36', NULL);
INSERT INTO \`temple_donation_campaigns\` (\`id\`, \`title_gu\`, \`title_hi\`, \`title_en\`, \`slug\`, \`description_gu\`, \`description_hi\`, \`description_en\`, \`writeup_gu\`, \`writeup_hi\`, \`writeup_en\`, \`goal_amount\`, \`raised_amount\`, \`donor_count\`, \`image_path\`, \`media\`, \`faqs\`, \`start_date\`, \`end_date\`, \`is_active\`, \`show_donor_list\`, \`is_featured\`, \`created_at\`, \`updated_at\`, \`deleted_at\`) VALUES ('2', 'ભોજનાલય વિસ્તરણ', 'भोजनालय विस्तारण', 'Bhojanalay Expansion', 'bhojanalay-expansion', 'દૈનિક ૫૦૦+ ભક્તોને ભોજન પ્રસાદ પીરસવા માટે ભોજનાલયનું વિસ્તરણ કરવામાં આવી રહ્યું છે.', NULL, NULL, NULL, NULL, NULL, '1000000.00', '320000.00', '78', NULL, NULL, NULL, '2026-03-03', '2026-07-31', '1', '1', '0', '2026-03-31 14:31:36', '2026-03-31 14:31:36', NULL);
